qry:select.qry:xquery:
for $r in sql(' SELECT PER02_BENEF_PER.oi_beneficio, per02_personal_emp.e_numero_legajo, PER01_PERSONAL.d_ape_y_nom, PER02_BENEF_PER.f_desde, PER02_BENEF_PER.f_hasta, ORG04_POSICIONES.oi_puesto, ORG04_POSICIONES.d_posicion, ORG18_CATEGORIAS.d_categoria, ORG18_CATEGORIAS.oi_convenio, PER02_BENEF_PER.n_valor, ORG03_EMPRESAS.d_empresa FROM PER02_BENEF_PER, PER02_PERSONAL_EMP, PER01_PERSONAL, ORG04_POSICIONES, ORG18_CATEGORIAS, ORG03_EMPRESAS
JOIN PER02_BENEF_PER.oi_personal_emp INNER PER02_PERSONAL_EMP.oi_personal_emp, PER02_PERSONAL_EMP.oi_personal INNER PER01_PERSONAL.oi_personal, PER02_PERSONAL_EMP.oi_posicion_ult LEFT OUTER ORG04_POSICIONES.oi_posicion, PER02_PERSONAL_EMP.oi_categoria_ult LEFT OUTER ORG18_CATEGORIAS.oi_categoria , PER02_PERSONAL_EMP.oi_empresa INNER ORG03_EMPRESAS.oi_empresa WHERE PER02_BENEF_PER.oi_beneficio = {%=#SOURCE:@oi_beneficio%} {%?(#PARAMIN:@f_desde != '') {% AND (PER02_BENEF_PER.f_hasta > {datetime(#PARAMIN:@f_desde)} OR ISNULL(PER02_BENEF_PER.f_hasta)) %} {% %} %} {%?(#PARAMIN:@f_hasta != '') {% AND PER02_BENEF_PER.f_desde < {datetime(#PARAMIN:@f_hasta)} %} {% %} %}
ORDER BY e_numero_legajo ASC ')/ROWS/ROW
